def classical_security(algorithm: str, key_bits: int) -> int:
    algo = algorithm.lower()
    if 'collision' in algo:
        return key_bits // 2
    return key_bits

def quantum_security(algorithm: str, key_bits: int) -> int:
    algo = algorithm.lower()
    if 'collision' in algo:
        return key_bits // 3
    return key_bits // 2

def required_key_size(target_quantum_security: int, algo_type: str) -> int:
    algo_type = algo_type.lower()
    if algo_type == 'symmetric' or algo_type == 'hash_preimage':
        return target_quantum_security * 2
    elif algo_type == 'hash_collision':
        return target_quantum_security * 3
    return target_quantum_security * 2

def security_assessment(algorithm: str, key_bits: int) -> dict:
    classical = classical_security(algorithm, key_bits)
    quantum = quantum_security(algorithm, key_bits)

    if quantum >= 128:
        status = 'SECURE'
    elif quantum >= 80:
        status = 'MARGINAL'
    else:
        status = 'INSECURE'

    return {
        'algorithm': algorithm,
        'key_bits': key_bits,
        'classical_security': classical,
        'quantum_security': quantum,
        'status': status
    }

import math

def grover_iterations(search_space_bits: int) -> int:
    N = 2 ** search_space_bits
    return int(math.pi / 4 * math.sqrt(N))

def total_oracle_calls(key_bits: int) -> float:
    # √(2^n) = 2^(n/2)
    return key_bits / 2

def compare_classical_quantum(key_bits: int) -> dict:
    classical_ops = key_bits  # 2^key_bits
    quantum_ops = key_bits / 2  # 2^(key_bits/2)
    speedup = classical_ops - quantum_ops

    return {
        'key_bits': key_bits,
        'classical_ops_log2': classical_ops,
        'quantum_ops_log2': quantum_ops,
        'speedup_factor_log2': speedup
    }

def time_estimate(key_bits: int, ops_per_second: float) -> dict:
    seconds_per_year = 365.25 * 24 * 60 * 60

    classical_ops = 2 ** key_bits
    quantum_ops = 2 ** (key_bits / 2)

    classical_years = classical_ops / ops_per_second / seconds_per_year
    quantum_years = quantum_ops / ops_per_second / seconds_per_year

    return {
        'classical_years': classical_years,
        'quantum_years': quantum_years
    }

def recommend_symmetric(use_case: str, data_sensitivity: str) -> dict:
    sensitivity_map = {
        'low': 128,
        'medium': 128,
        'high': 192,
        'top_secret': 256
    }

    target_quantum_bits = sensitivity_map.get(data_sensitivity, 128)
    required_key = target_quantum_bits * 2

    if use_case == 'high_performance':
        algorithm = 'ChaCha20-Poly1305'
        reasoning = 'Best software performance'
    elif use_case == 'embedded':
        algorithm = 'AES-GCM'
        reasoning = 'Hardware acceleration available'
    else:
        algorithm = 'AES-GCM'
        reasoning = 'Industry standard, widely supported'

    return {
        'algorithm': algorithm,
        'key_size': required_key,
        'mode': 'authenticated',
        'quantum_security_bits': target_quantum_bits,
        'reasoning': reasoning
    }

def recommend_hash(use_case: str) -> dict:
    recommendations = {
        'general': ('SHA-256', 256, '128-bit quantum preimage resistance'),
        'signatures': ('SHA-384', 384, '192-bit quantum security for signatures'),
        'password': ('Argon2id', 256, 'Memory-hard, quantum-resistant'),
        'collision_resistant': ('SHA-512', 512, '170-bit quantum collision resistance')
    }

    algo, bits, reason = recommendations.get(use_case, recommendations['general'])

    return {
        'algorithm': algo,
        'output_bits': bits,
        'quantum_preimage_security': bits // 2,
        'quantum_collision_security': bits // 3,
        'reasoning': reason
    }

def migration_plan(current_config: dict) -> dict:
    plan = {'changes': [], 'priority': 'LOW'}

    # Check symmetric
    if 'symmetric' in current_config:
        sym = current_config['symmetric']
        if sym.get('key_size', 0) < 256:
            plan['changes'].append({
                'component': 'symmetric',
                'current': sym,
                'recommended': recommend_symmetric('general', 'high'),
                'urgency': 'MEDIUM'
            })
            plan['priority'] = 'MEDIUM'

    # Check hash
    if 'hash' in current_config:
        h = current_config['hash']
        if h.get('output_bits', 0) < 256:
            plan['changes'].append({
                'component': 'hash',
                'current': h,
                'recommended': recommend_hash('general'),
                'urgency': 'HIGH'
            })
            plan['priority'] = 'HIGH'

    return plan

def analyze_algorithm(name: str, key_bits: int) -> dict:
    name_upper = name.upper()

    # Shor-vulnerable algorithms
    shor_targets = ['RSA', 'ECDSA', 'ECDH', 'DH', 'DSA', 'ELGAMAL']

    shor_vulnerable = any(t in name_upper for t in shor_targets)

    if shor_vulnerable:
        return {
            'algorithm': name,
            'key_bits': key_bits,
            'shor_vulnerable': True,
            'grover_impact': 'N/A',
            'quantum_security': 0,
            'threat': 'CRITICAL',
            'recommendation': 'Replace with PQC algorithm (Kyber, Dilithium)'
        }
    else:
        quantum_sec = key_bits // 2
        if quantum_sec >= 128:
            threat = 'LOW'
            rec = 'Current parameters are quantum-safe'
        elif quantum_sec >= 80:
            threat = 'MEDIUM'
            rec = 'Consider increasing key size'
        else:
            threat = 'HIGH'
            rec = 'Increase to 256-bit key immediately'

        return {
            'algorithm': name,
            'key_bits': key_bits,
            'shor_vulnerable': False,
            'grover_impact': f'{key_bits}-bit → {quantum_sec}-bit',
            'quantum_security': quantum_sec,
            'threat': threat,
            'recommendation': rec
        }

def compare_threats() -> dict:
    return {
        'shors_algorithm': {
            'speedup': 'Exponential',
            'effect': 'Complete break',
            'targets': ['RSA', 'ECC', 'DH', 'DSA'],
            'mitigation': 'New algorithms required',
            'urgency': 'CRITICAL'
        },
        'grovers_algorithm': {
            'speedup': 'Quadratic',
            'effect': 'Halves security',
            'targets': ['AES', 'ChaCha20', 'SHA-2', 'SHA-3'],
            'mitigation': 'Double key/output sizes',
            'urgency': 'MODERATE'
        }
    }

def prioritize_migration(algorithms: list) -> list:
    analyzed = []
    for name, bits in algorithms:
        analysis = analyze_algorithm(name, bits)

        # Priority score (higher = more urgent)
        if analysis['shor_vulnerable']:
            priority = 100
        elif analysis['quantum_security'] < 64:
            priority = 80
        elif analysis['quantum_security'] < 128:
            priority = 50
        else:
            priority = 10

        analysis['priority_score'] = priority
        analyzed.append(analysis)

    return sorted(analyzed, key=lambda x: x['priority_score'], reverse=True)
